import { Link } from "react-router-dom";

function Dashboard() {
  return (
    <div>
      <h1>Dashboard</h1>
      <Link to="/book">Book Appointment</Link>
      <br />
      <Link to="/appointments">View Appointments</Link>
    </div>
  );
}

export default Dashboard;
